    "title": "Guided Practice",
    "objective": "Categorize a specific energy source and a transmission voltage from a site description.",
    "retrievalTextLines": [
      "Recall the standard UK transmission voltages: 132 kV, 275 kV, and 400 kV.",
      "Generation methods include renewables like wind and wave, as well as traditional sources like gas and nuclear.",
      "Look for the 'kV' rating to identify transmission and the energy source to identify generation."
    ],
    "questionText": "A site report identifies a 'Wave energy converter' and a '400 kV substation'. Identify which of these is the generation method and which is the transmission voltage.",
    "answerGuidance": [
      "Wave energy converter is the generation method",
      "400 kV is the transmission voltage"
    ],
    "hint": "Check the voltage against the 'big three' (132, 275, 400). If it matches, it's transmission. If it's a way of making power, it's generation."
  },
  "practice": {
    "title": "Practice",
    "objective": "Independently identify the remaining UK transmission voltage and a valid generation method.",
    "retrievalTextLines": [
      "The UK National Grid uses three specific high-voltage levels for transmission.",
      "You must be able to distinguish valid generation methods from distribution equipment or incorrect voltage levels."
    ],
    "questionText": "The UK transmission system uses 400 kV and 275 kV. State the third standard transmission voltage and identify which of the following is a valid generation method: '11 kV Transformer' or 'Hydro-electric plant'.",
    "answerGuidance": [
      "132 kV",
      "Hydro-electric plant"
    ],
    "hint": "Transmission voltages are always 132 kV or higher in the UK. Remember that a transformer is a component, not a method of generating electricity."
  }
}

